package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JsonPrimitiveTest {

  private JsonPrimitive jsonPrimitive;

  @BeforeEach
  public void setUp() {
    // We will instantiate JsonPrimitive via reflection since constructors are not fully shown.
    // We'll create a subclass to access protected constructor if needed or use reflection to set 'value' field.
  }

  @Test
  public void testGetAsFloat_whenValueIsNumber() throws Exception {
    // Create JsonPrimitive with a Number value (e.g. Double)
    jsonPrimitive = new JsonPrimitive(3.14d);

    float result = jsonPrimitive.getAsFloat();

    assertEquals(3.14f, result, 0.0001f);
  }

  @Test
  public void testGetAsFloat_whenValueIsLazilyParsedNumber() throws Exception {
    // LazilyParsedNumber is internal, create instance via constructor
    Object lazilyParsedNumber = new LazilyParsedNumber("2.718");

    jsonPrimitive = new JsonPrimitive((Number) lazilyParsedNumber);

    float result = jsonPrimitive.getAsFloat();

    assertEquals(2.718f, result, 0.0001f);
  }

  @Test
  public void testGetAsFloat_whenValueIsStringNumber() throws Exception {
    // Create JsonPrimitive with a String representing a number
    jsonPrimitive = new JsonPrimitive("1.234");

    float result = jsonPrimitive.getAsFloat();

    assertEquals(1.234f, result, 0.0001f);
  }

  @Test
  public void testGetAsFloat_whenValueIsStringNonNumber_throwsNumberFormatException() throws Exception {
    jsonPrimitive = new JsonPrimitive("notANumber");

    assertThrows(NumberFormatException.class, () -> {
      jsonPrimitive.getAsFloat();
    });
  }

  @Test
  public void testGetAsFloat_whenValueIsIntegerNumber() throws Exception {
    jsonPrimitive = new JsonPrimitive(42);

    float result = jsonPrimitive.getAsFloat();

    assertEquals(42f, result, 0.0001f);
  }

  @Test
  public void testGetAsFloat_whenValueIsFloatNumber() throws Exception {
    jsonPrimitive = new JsonPrimitive(5.5f);

    float result = jsonPrimitive.getAsFloat();

    assertEquals(5.5f, result, 0.0001f);
  }

  // Helper constructors to instantiate JsonPrimitive with different types
  private static class JsonPrimitive extends com.google.gson.JsonPrimitive {
    JsonPrimitive(Boolean bool) {
      super(bool);
    }
    JsonPrimitive(Number number) {
      super(number);
    }
    JsonPrimitive(String string) {
      super(string);
    }
    JsonPrimitive(Character c) {
      super(c);
    }
  }
}
